rb_run_threshold &lt;-
  run_ipaa |&gt;
  dplyr::filter(position == "RB") |&gt;
  dplyr::arrange(desc(n_run)) |&gt;
  dplyr::slice(96) |&gt;
  dplyr::pull(n_run)


run_ipaa &lt;-
  run_ipaa |&gt;
  dplyr::mutate(
    repl_wrte = dplyr::case_when(
      position %in% c("WR", "TE") & n_run &lt; wrte_run_threshold ~ 1,
      position %in% c("WR", "TE") & n_run &gt;= wrte_run_threshold ~ 0,
      !position %in% c("WR", "TE") ~ NA),
    repl_rb = dplyr::case_when(
      position == "RB" & n_run &lt; rb_run_threshold ~ 1,
      position == "RB" & n_run &gt;= rb_run_threshold ~ 0,
      position != "RB" ~ NA))



repl_wrte_ipa_run &lt;- 
  run_ipaa |&gt;
  dplyr::filter(repl_wrte == 1) |&gt;
  dplyr::pull(ipa_run) |&gt;
  mean(na.rm = TRUE)
repl_rb_ipa_run &lt;-
  run_ipaa |&gt;
  dplyr::filter(repl_rb == 1) |&gt;
  dplyr::pull(ipa_run) |&gt;
  mean(na.rm = TRUE)


run_ipar &lt;-
  run_ipaa |&gt;
  dplyr::filter(position %in% c("WR", "RB", "TE")) |&gt;
   dplyr::mutate(
    shadow_run = dplyr::case_when(
      position %in% c("WR", "TE") ~ n_run * repl_wrte_ipa_run,
      position == "RB" ~ n_run * repl_rb_ipa_run),
    ipar_run = ipaa_run - shadow_run)




Computing IPAR for QB’s
We defined replacement-levels for running backs, wide receivers, and tight ends based on typical patterns of roster construction. Due to the unique nature of the quarterback position — virtually every offensive play involves runs through the quarterback — we need to define “replacement” level somewhat differently. One option would be to create a group of 32 non-replacement quarterbacks by identifying the quarterback one each team who were involved in the most passing and rushing attempts. While simple to implement, this implicitly assumes that every NFL team has at least one non-replacement quarterback. Instead, we sort quarterbacks by the total number of passing and rushing plays in which they were involved and designate the top-32 to be non-replacement level.

qb_ipaa &lt;-
  passer_ipaa |&gt;
  dplyr::filter(position == "QB") |&gt;
  dplyr::select(gsis_id, full_name, n_pass, ipa_air_pass, ipaa_air_pass) |&gt;
  dplyr::left_join(y = qbrun_ipaa |&gt; dplyr::select(gsis_id, n_qbrun, ipa_qbrun, ipaa_qbrun), by = "gsis_id") |&gt;
  dplyr::mutate(n_plays = n_pass + n_qbrun)

qb_threshold &lt;-
  qb_ipaa |&gt;
  dplyr::arrange(dplyr::desc(n_plays)) |&gt;
  dplyr::slice(32) |&gt;
  dplyr::pull(n_plays)

qb_ipaa &lt;-
  qb_ipaa |&gt;
  dplyr::mutate(repl_qb = ifelse(n_plays &lt; qb_threshold, 1, 0))

repl_qb_ipa_air &lt;-
  qb_ipaa |&gt;
  dplyr::filter(repl_qb == 1) |&gt;
  dplyr::pull(ipa_air_pass) |&gt;
  mean(na.rm = TRUE)

repl_qb_ipa_qbrun &lt;-
  qb_ipaa |&gt;
  dplyr::filter(repl_qb == 1) |&gt;
  dplyr::pull(ipa_qbrun) |&gt;
  mean(na.rm = TRUE)

qb_ipar &lt;-
  qb_ipaa |&gt;
  dplyr::mutate(
    shadow_air = n_pass * repl_qb_ipa_air,
    shadow_qbrun = n_qbrun * repl_qb_ipa_qbrun,
    ipar_air_pass = ipaa_air_pass - shadow_air,
    ipar_qbrun = ipaa_qbrun - shadow_qbrun)

Fielding Run Values
If a ball is hit towards deep left field and results in the fielding team creating a large \(-\delta\), how much blame should the third baseman, who is on the opposite side of the park receive? Following Baumer et al. (2015), we will apportion \(\delta_{i}^{(f)},\) the portion of the run value \(-\delta_{i}\) attributable to the fielding in at-bat \(i\), based on each fielder’s responsibility for making an out on the batted ball. Specifically, we will assign \(w_{i,\ell} \times \delta_{i}^{(f)}\) to the fielder playing position \(\ell \in \{1, 2, \ldots, 9\}\) during the at-bat where \[
w_{i,\ell} = \frac{\hat{p}_{i,\ell}}{\hat{p}_{i,1} + \cdots + \hat{p}_{i,9}}
\] and \(\hat{p}_{i,\ell}\) is the probability that fielder \(\ell\) makes the out given the location of the batted ball.
To estimate the \(\hat{p}_{i,\ell}\)’s, we will fit 9 separate GAMs, one for each fielding position. For fielding position \(\ell,\) we will create a new variable that is equal to 1 if the ball in play resulted in an out was initially fielded by the player at position \(\ell.\) Unlike our overall out probability model, which we fit using data from all batted balls, each position-specific GAM will be fitted using data from the subset of batted balls that are reasonably close to the typical position location. For instance, when fitting the model for the first basemen, we won’t include data from balls hit into deep left field. We compute the coordinates of the typical position by taking the average value of the x and y coordinates of all batted balls fielded by players at position \(\ell.\) We fit each position-specific GAM using batted balls hit within 150 ft of this typical location3






ImportantWarning



This code takes between several minutes to run



