mid_y &lt;- rep(NA, times = 9)
2fit_list &lt;- list()
fit_time &lt;- rep(NA, times = 9)
for(l in 1:9){
  print(paste0("Starting l = ", Sys.time()))

3  mid_x[l] &lt;- mean(bip$x[bip$end_hit_location == l], na.rm = TRUE)
  mid_y[l] &lt;- mean(bip$y[bip$end_hit_location==l], na.rm = TRUE)

  train_df &lt;-
    bip |&gt;
4    dplyr::mutate(newOut = ifelse(Out == 1 & end_hit_location == l, 1, 0)) |&gt;
    dplyr::filter(!is.na(x) & !is.na(y)) |&gt;
5    dplyr::filter( sqrt( (x - mid_x[l])^2 + (y - mid_y[l])^2 ) &lt; 150) |&gt;
    dplyr::select(x,y,newOut) 

6  fit_time[l] &lt;-
    system.time(
7      fit_list[[l]] &lt;-
        bam(formula = newOut ~ s(x, y),
8            family = binomial(link="logit"),data = train_df))["elapsed"]
  tmp_df &lt;-
    def_atbat2024 |&gt; 
    dplyr::mutate(
9      x = ifelse(sqrt( (x - mid_x[l])^2 + (y - mid_y[l])^2 ) &lt; 150, x, NA),
      y = ifelse(sqrt( (x - mid_x[l])^2 + (y - mid_y[l])^2 ) &lt; 150, y, NA)
    )

10  preds &lt;- predict(object = fit_list[[l]], newdata = tmp_df, type = "response")
11  def_atbat2024[[paste0("p_out_", l)]] &lt;- preds
}
12save(fit_list, mid_x, mid_y, file = "position_gam_fits.RData")


